    uint32_t padDepth = static_cast<uint32_t>(padding->GetData()[0]);
    uint32_t padHeight = static_cast<uint32_t>(padding->GetData()[1]);
    uint32_t padWidth = static_cast<uint32_t>(padding->GetData()[2]);

    uint32_t depthOut = ComputeSize(depthIn, kernelDepth, strideDepth, padDepth, ceilMode);
    uint32_t heightOut = ComputeSize(heightIn, kernelHeight, strideHeight, padHeight, ceilMode);
    uint32_t widthOut = ComputeSize(widthIn, kernelWidth, strideWidth, padWidth, ceilMode);
    uint32_t totalOut = batchSize * channels * depthOut * heightOut * widthOut;

    uint32_t blockDim = 8;
    context->SetBlockDim(blockDim);

    tiling.set_batchSize(batchSize);
    tiling.set_channels(channels);
    tiling.set_depthIn(depthIn);
    tiling.set_heightIn(heightIn);
    tiling.set_widthIn(widthIn);
    tiling.set_kernelDepth(kernelDepth);
    tiling.set_kernelHeight(kernelHeight);
    tiling.set_kernelWidth(kernelWidth);
    tiling.set_strideDepth(strideDepth);
    tiling.set_strideHeight(strideHeight);
    tiling.set_strideWidth(strideWidth);
    tiling.set_padDepth(padDepth);
    tiling.set_padHeight(padHeight);
    tiling.set_padWidth(padWidth);
    tiling.set_ceilMode(static_cast<uint8_t>(ceilMode));
    tiling.set_depthOut(depthOut);
    tiling.set_heightOut(heightOut);
    tiling.set_widthOut(widthOut);
    tiling.set_totalOut(totalOut);
    tiling.set_blockDim(blockDim);

    tiling.SaveToBuffer(context->GetRawTilingData()->GetData(),
                        context->GetRawTilingData()->GetCapacity());
    context->GetRawTilingData()->SetDataSize(tiling.GetDataSize());

    size_t *currentWorkspace = context->GetWorkspaceSizes(1);
